module RefModule(
    input A,
    input B,
    input CLK,
    input EN,
    input CLR,
    output reg X,
    output reg Y
);reg unused_X_buf;
    reg Y_buf;
    reg [1:0] state;

    always @(posedge CLK) begin
        if (CLR) begin
            unused_X_buf <= 0;
            Y_buf <= 0;
            state <= 0;
        end else if (EN) begin
            case (state)
                0: begin
                    unused_X_buf <= A;
                    Y_buf <= B;
                    state <= 1;
                end
                1: begin
                    unused_X_buf <= unused_X_buf;
                    Y_buf <= Y_buf;
                    state <= 2;
                end
                2: begin
                    unused_X_buf <= unused_X_buf;
                    Y_buf <= Y_buf;
                    state <= 0;
                end
            endcase
        end
    end

    assign X = unused_X_buf;
    assign Y = Y_buf;

endmodule
